#!/usr/bin/env bash
# apply-v0.3.2.sh — SSOT化（schema meta → AIプロンプト型表／helpのCONSTRAINT_RULES生成）
#                    ＋ テンプレ・sample.md の round-trip 検証テスト追加
# 前提: apply-v0.3.1.sh 適用済み（src/schema/{chart,diagram,timeline,steps,contrast,feature}.ts が
#       .meta({id, summary, ...}) 形式で存在する）
# 冪等（1回目=OK・2回目=SKIP）。実行後に typecheck / vitest / eslint / prettier まで通す。
#
# 方針: v0.3.1に続き「検証済みファイル全体をbase64で埋め込み、マーカーの有無で冪等性判定」方式。
# 今回はschema6ファイルの.meta()形状統一（SlideTypeMeta化）＋新規registry/describe/roundtrip test＋
# draftAssistPrompt.ts/helpContent.tsの生成呼び出し配線、の計12ファイルが対象。
set -euo pipefail
cd "$(dirname "$0")/.."

MARKER_META='// v0.3.2-meta-unified'
MARKER_SSOT='// v0.3.2-ssot-applied'

# ---------------------------------------------------------------------------
# 0. 前提チェック
# ---------------------------------------------------------------------------
for f in src/schema/chart.ts src/schema/diagram.ts src/schema/timeline.ts src/schema/steps.ts src/schema/contrast.ts src/schema/feature.ts; do
  if [ ! -f "$f" ]; then
    echo "[ERROR] $f がありません。先に apply-v0.3.0.sh / apply-v0.3.1.sh を適用してください"
    exit 1
  fi
done

# ---------------------------------------------------------------------------
# 1. src/schema/{chart,diagram,timeline,steps,contrast,feature}.ts を
#    SlideTypeMeta統一形状（id/slideTypes/summary/constraints/layouts?）へ全置換
# ---------------------------------------------------------------------------
if grep -q "$MARKER_META" "src/schema/chart.ts" 2>/dev/null; then
  echo "[SKIP] src/schema/chart.ts: already v0.3.2 (meta unified)"
else
  cp "src/schema/chart.ts" "/tmp/$(basename src/schema/chart.ts).pre-v0.3.2.bak"
  echo "" | base64 -d > "src/schema/chart.ts"
  if ! grep -q "$MARKER_META" "src/schema/chart.ts"; then
    echo "[ERROR] src/schema/chart.ts: マーカー埋め込みに失敗しました。/tmp/$(basename src/schema/chart.ts).pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/schema/chart.ts updated (meta統一形状)"
fi
if grep -q "$MARKER_META" "src/schema/diagram.ts" 2>/dev/null; then
  echo "[SKIP] src/schema/diagram.ts: already v0.3.2 (meta unified)"
else
  cp "src/schema/diagram.ts" "/tmp/$(basename src/schema/diagram.ts).pre-v0.3.2.bak"
  echo "" | base64 -d > "src/schema/diagram.ts"
  if ! grep -q "$MARKER_META" "src/schema/diagram.ts"; then
    echo "[ERROR] src/schema/diagram.ts: マーカー埋め込みに失敗しました。/tmp/$(basename src/schema/diagram.ts).pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/schema/diagram.ts updated (meta統一形状)"
fi
if grep -q "$MARKER_META" "src/schema/timeline.ts" 2>/dev/null; then
  echo "[SKIP] src/schema/timeline.ts: already v0.3.2 (meta unified)"
else
  cp "src/schema/timeline.ts" "/tmp/$(basename src/schema/timeline.ts).pre-v0.3.2.bak"
  echo "" | base64 -d > "src/schema/timeline.ts"
  if ! grep -q "$MARKER_META" "src/schema/timeline.ts"; then
    echo "[ERROR] src/schema/timeline.ts: マーカー埋め込みに失敗しました。/tmp/$(basename src/schema/timeline.ts).pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/schema/timeline.ts updated (meta統一形状)"
fi
if grep -q "$MARKER_META" "src/schema/steps.ts" 2>/dev/null; then
  echo "[SKIP] src/schema/steps.ts: already v0.3.2 (meta unified)"
else
  cp "src/schema/steps.ts" "/tmp/$(basename src/schema/steps.ts).pre-v0.3.2.bak"
  echo "" | base64 -d > "src/schema/steps.ts"
  if ! grep -q "$MARKER_META" "src/schema/steps.ts"; then
    echo "[ERROR] src/schema/steps.ts: マーカー埋め込みに失敗しました。/tmp/$(basename src/schema/steps.ts).pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/schema/steps.ts updated (meta統一形状)"
fi
if grep -q "$MARKER_META" "src/schema/contrast.ts" 2>/dev/null; then
  echo "[SKIP] src/schema/contrast.ts: already v0.3.2 (meta unified)"
else
  cp "src/schema/contrast.ts" "/tmp/$(basename src/schema/contrast.ts).pre-v0.3.2.bak"
  echo "" | base64 -d > "src/schema/contrast.ts"
  if ! grep -q "$MARKER_META" "src/schema/contrast.ts"; then
    echo "[ERROR] src/schema/contrast.ts: マーカー埋め込みに失敗しました。/tmp/$(basename src/schema/contrast.ts).pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/schema/contrast.ts updated (meta統一形状)"
fi
if grep -q "$MARKER_META" "src/schema/feature.ts" 2>/dev/null; then
  echo "[SKIP] src/schema/feature.ts: already v0.3.2 (meta unified)"
else
  cp "src/schema/feature.ts" "/tmp/$(basename src/schema/feature.ts).pre-v0.3.2.bak"
  echo "" | base64 -d > "src/schema/feature.ts"
  if ! grep -q "$MARKER_META" "src/schema/feature.ts"; then
    echo "[ERROR] src/schema/feature.ts: マーカー埋め込みに失敗しました。/tmp/$(basename src/schema/feature.ts).pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/schema/feature.ts updated (meta統一形状)"
fi

# ---------------------------------------------------------------------------
# 2. src/schema/registry.ts / describe.ts / roundtrip.test.ts を新規作成
# ---------------------------------------------------------------------------
if [ -f "src/schema/registry.ts" ]; then
  echo "[SKIP] src/schema/registry.ts already exists"
else
  echo "" | base64 -d > "src/schema/registry.ts"
  echo "[OK] src/schema/registry.ts created"
fi
if [ -f "src/schema/describe.ts" ]; then
  echo "[SKIP] src/schema/describe.ts already exists"
else
  echo "" | base64 -d > "src/schema/describe.ts"
  echo "[OK] src/schema/describe.ts created"
fi
if [ -f "src/schema/roundtrip.test.ts" ]; then
  echo "[SKIP] src/schema/roundtrip.test.ts already exists"
else
  echo "" | base64 -d > "src/schema/roundtrip.test.ts"
  echo "[OK] src/schema/roundtrip.test.ts created"
fi

# ---------------------------------------------------------------------------
# 3. src/schema/chart.test.ts を更新（旧 maxSeries キー参照テストを新形状へ）
# ---------------------------------------------------------------------------
if grep -q "$MARKER_SSOT" src/schema/chart.test.ts 2>/dev/null; then
  echo "[SKIP] src/schema/chart.test.ts: already v0.3.2"
else
  cp src/schema/chart.test.ts "/tmp/chart.test.ts.pre-v0.3.2.bak"
  echo "" | base64 -d > src/schema/chart.test.ts
  echo "[OK] src/schema/chart.test.ts updated"
fi

# ---------------------------------------------------------------------------
# 4. src/ai/draftAssistPrompt.ts を全置換（型別詳細仕様セクションを自動生成に）
# ---------------------------------------------------------------------------
if grep -q "$MARKER_SSOT" src/ai/draftAssistPrompt.ts 2>/dev/null; then
  echo "[SKIP] src/ai/draftAssistPrompt.ts: already v0.3.2"
else
  cp src/ai/draftAssistPrompt.ts "/tmp/draftAssistPrompt.ts.pre-v0.3.2.bak"
  echo "" | base64 -d > src/ai/draftAssistPrompt.ts
  if ! grep -q "$MARKER_SSOT" src/ai/draftAssistPrompt.ts; then
    echo "[ERROR] draftAssistPrompt.ts: マーカー埋め込みに失敗しました。/tmp/draftAssistPrompt.ts.pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/ai/draftAssistPrompt.ts patched"
fi

# ---------------------------------------------------------------------------
# 5. src/help/helpContent.ts を全置換（CONSTRAINT_RULESをschema生成＋deck手書きに再構成）
# ---------------------------------------------------------------------------
if grep -q "$MARKER_SSOT" src/help/helpContent.ts 2>/dev/null; then
  echo "[SKIP] src/help/helpContent.ts: already v0.3.2"
else
  cp src/help/helpContent.ts "/tmp/helpContent.ts.pre-v0.3.2.bak"
  echo "" | base64 -d > src/help/helpContent.ts
  if ! grep -q "$MARKER_SSOT" src/help/helpContent.ts; then
    echo "[ERROR] helpContent.ts: マーカー埋め込みに失敗しました。/tmp/helpContent.ts.pre-v0.3.2.bak から復元してください"
    exit 1
  fi
  echo "[OK] src/help/helpContent.ts patched"
fi

# ---------------------------------------------------------------------------
# 6. 検証
# ---------------------------------------------------------------------------
echo '--- verify (grep) ---'
test -f src/schema/registry.ts && echo '[OK] src/schema/registry.ts exists'
test -f src/schema/describe.ts && echo '[OK] src/schema/describe.ts exists'
test -f src/schema/roundtrip.test.ts && echo '[OK] src/schema/roundtrip.test.ts exists'
grep -q "buildTypeReferenceTable" src/ai/draftAssistPrompt.ts && echo '[OK] draftAssistPrompt.ts uses buildTypeReferenceTable'
grep -q "buildConstraintRules" src/help/helpContent.ts && echo '[OK] helpContent.ts uses buildConstraintRules'

echo '--- typecheck ---'
npx tsc -b --noEmit

echo '--- vitest ---'
npx vitest run

echo '--- eslint ---'
npx eslint src

echo '--- prettier（今回変更ファイルのみ）---'
npx prettier --check src/schema/chart.ts src/schema/diagram.ts src/schema/timeline.ts \
  src/schema/steps.ts src/schema/contrast.ts src/schema/feature.ts \
  src/schema/registry.ts src/schema/describe.ts src/schema/roundtrip.test.ts \
  src/schema/chart.test.ts src/ai/draftAssistPrompt.ts src/help/helpContent.ts

echo '=== apply-v0.3.2.sh completed ==='
